onClick:
{{
  (() => {
    // 1. Valida se o número da denúncia foi preenchido
    if (!n_denuncia_Autista.text) {
      return showAlert('Por favor, preencha o número da denúncia.', 'warning');
    }

    // 2. Valida se o texto da denúncia foi preenchido
    if (!Text_den_Autista.text) {
      return showAlert('Por favor, preencha a descrição/texto da denúncia.', 'warning');
    }

    // 3. Executa a query de inserção direta no banco
    return Query_Salvar_Autista.run()
      .then(() => {
        // Lista de campos com os nomes exatos do Autista para limpar automaticamente
        const camposParaLimpar = [
          "n_denuncia_Autista",
          "data_e_hora_denuncia_Autista", 
          "Data_Reg_Autista",
          "Hora_Reg_Autista",
          "Denunciante_Autista",
          "Agressor_Autista",
          "Testemunha_Autista",
          "Localizacao_Autista",
          "Resposta_Denunciante_Autista",
          "Text_den_Autista",
          "telefone_Autista",
          "email_Autista",
          "classif_denun_Autista"
        ];

        // Executa a limpeza individual de cada componente
        camposParaLimpar.forEach(async (campo) => {
          try {
            await resetWidget(campo, true);
          } catch(e) {}
        });

        showAlert('Denúncia cadastrada e campos limpos com sucesso!', 'success');
      })
      .catch((err) => {
        showAlert('Erro ao salvar as informações: ' + (err?.message || err), 'error');
      });
  })()
}}
